        for (int i = 0; i < label_count; ++i) {
            if (label_keys[i] == NULL || label_values[i] == NULL) {
                return -1;
            }
        }
    }

    if (label_count == 0) {
        // Just write the metric name without braces
        int len = sprintf(metric_output, "%s", metric_name);
        if (len < 0) {
            return -1;
        }
        return len;
    }

    int total_len = 0;
    // Write metric name and opening brace
    int len = sprintf(metric_output, "%s{", metric_name);
    if (len < 0) {
        return -1;
    }
    total_len += len;

    // Write each label key-value pair
    for (int i = 0; i < label_count; ++i) {
        const char* fmt = (i == 0) ? "%s=\"%s\"" : ",%s=\"%s\"";
        len = sprintf(metric_output + total_len, fmt, label_keys[i], label_values[i]);
        if (len < 0) {
            return -1;
        }
        total_len += len;
    }

    // Write closing brace
    len = sprintf(metric_output + total_len, "}");
    if (len < 0) {
        return -1;
    }
    total_len += len;

    return total_len;
}
